(() => {
    type FieldFor<T> = T extends string
      ? {kind: 'text'; value: string}
      : T extends number
        ? {kind: 'number'; value: number; min?: number}
        : T extends boolean
          ? {kind: 'checkbox'; value: boolean}
          : never;
    interface User {
      name: string;
      age: number;
      admin: boolean;
    }
    type UserForm = {[K in keyof User]: FieldFor<User[K]>};
    return {build: () => createValidate<UserForm>(), buildErrors: () => noErrs(createGetValidationErrors<UserForm>())};
  })()

c(z.object({
    name: z.object({kind: z.literal('text'), value: z.string()}),
    age: z.object({kind: z.literal('number'), value: z.number().finite(), min: z.number().finite().optional()}),
    admin: z.object({kind: z.literal('checkbox'), value: z.boolean()}),
  }))

c(
    Type.Object({
      name: Type.Object({kind: Type.Literal('text'), value: Type.String()}),
      age: Type.Object({kind: Type.Literal('number'), value: Type.Number(), min: Type.Optional(Type.Number())}),
      admin: Type.Object({kind: Type.Literal('checkbox'), value: Type.Boolean()}),
    })
  )

c({
      type: 'object',
      properties: {
        name: {
          type: 'object',
          properties: {kind: {const: 'text'}, value: {type: 'string'}},
          required: ['kind', 'value'],
        },
        age: {
          type: 'object',
          properties: {kind: {const: 'number'}, value: {type: 'number'}, min: {type: 'number'}},
          required: ['kind', 'value'],
        },
        admin: {
          type: 'object',
          properties: {kind: {const: 'checkbox'}, value: {type: 'boolean'}},
          required: ['kind', 'value'],
        },
      },
      required: ['name', 'age', 'admin'],
    })
